<?php require_once dirname(__DIR__) . '/includes/auth.php'; require_admin(); $pdo=db();
if(($_SERVER['REQUEST_METHOD']??'')==='POST'){
 if(isset($_POST['toggle'])){$pdo->prepare('UPDATE email_sequences SET status=IF(status="active","paused","active") WHERE id=?')->execute([$_POST['id']]);}
 else{$pdo->prepare('INSERT INTO email_sequences (client_id,name,status,description) VALUES (?,?,?,?)')->execute([$_POST['client_id'],$_POST['name'],$_POST['status'],$_POST['description']]);}
}
$clients=$pdo->query('SELECT * FROM clients ORDER BY name')->fetchAll(); $rows=$pdo->query('SELECT s.*,c.name client_name FROM email_sequences s JOIN clients c ON c.id=s.client_id ORDER BY s.id DESC')->fetchAll(); include '_header.php'; ?>
<h1>Email Sequences</h1><div class="card"><h2>Add Sequence</h2><form method="post"><select name="client_id" required><?php foreach($clients as $c): ?><option value="<?=$c['id']?>"><?=e($c['name'])?></option><?php endforeach; ?></select><input name="name" placeholder="Sequence name" required><select name="status"><option>paused</option><option>active</option></select><textarea name="description" placeholder="Description"></textarea><button>Add</button></form></div><table><tr><th>ID</th><th>Client</th><th>Name</th><th>Status</th><th></th></tr><?php foreach($rows as $r): ?><tr><td><?=$r['id']?></td><td><?=e($r['client_name'])?></td><td><?=e($r['name'])?></td><td><?=e($r['status'])?></td><td><form method="post"><input type="hidden" name="id" value="<?=$r['id']?>"><button name="toggle" value="1">Pause/Activate</button></form></td></tr><?php endforeach; ?></table><?php include '_footer.php'; ?>
